+ 
++/* Some Turbo "unit crt" functions. */
++
++#include <curses.h>
++#include <term.h>
++
++static int terminfo_initialized;
++static char *cl, *ce;
++
++static void initcurs()
++{
++    if (terminfo_initialized)
++	return;
++    setupterm(0, fileno(stdout), 0);
++    ce = tgetstr("ce", 0);
++    cl = tgetstr("cl", 0);
++    terminfo_initialized = 1;
++}
++
++void clreol()
++{
++    initcurs();
++    if (ce)
++	tputs(ce, 1, putchar);
++}
++
++void clrscr()
++{
++    initcurs();
++    if (cl)
++	tputs(cl, 1, putchar);
++}
++
++void delay(ms)
++int ms;
++{
++    usleep(1000 * ms);
++}
++
